import 'package:flutter/cupertino.dart';import 'package:flutter/material.dart';import '../../core/constants/app_color.dart';import '../../core/constants/data_constant.dart';import '../../core/constants/dimesions.dart';import '../../models/noti_model.dart';class NotiCard extends StatelessWidget {  final NotiData notiData;  const NotiCard({super.key, required this.notiData});  @override  Widget build(BuildContext context) {    return Container(        margin: EdgeInsets.only(top: Dimesion.width5),        padding: EdgeInsets.all(Dimesion.width5),        decoration: BoxDecoration(            border: Border.all(color: AppColor.blackless,width: 1),            color: notiData.readAt!=null?AppColor.bgColor:Colors.grey[100],            borderRadius: BorderRadius.circular(Dimesion.width5)),        child: Row(          mainAxisAlignment: MainAxisAlignment.spaceBetween,          children: [            Icon(Icons.notifications),            Text(              notiData.data ?? "",              style: TextStyle(color: AppColor.black,fontSize: Dimesion.font12+1,fontWeight: FontWeight.bold),            ),            Column(              mainAxisAlignment: MainAxisAlignment.spaceBetween,              children: [                notiData.readAt == null                    ? Icon(Icons.circle,                    color: Colors.green, size: Dimesion.radius15 / 2)                    : SizedBox(),                SizedBox(                  height: Dimesion.height20,                ),                Text(DataConstant.dateFormat.format(DateTime.parse(notiData.updatedAt!)),)              ],            )          ],        ));  }}